   118|      where('isActive', '==', true),
   119|      orderBy('createdAt', 'desc')
   120|    );
   121|    const snap = await getDocs(q);
   122|    const items = snap.docs.map(d => parseEquipment(d.id, d.data() as Record<string, unknown>));
   123|    console.log('[Firestore] Fetched', items.length, 'equipment items (indexed)');
   124|    return items;
   125|  } catch (indexError: unknown) {
   126|    console.warn('[Firestore] Indexed query failed, falling back to simple query:', indexError);
   127|    try {
